export interface UserCreateInput {
  name: string;
  email: string;
  role?: 'admin' | 'member' | 'viewer';
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: string;
  createdAt: Date;
}

export class UserService {
  constructor(private db: Database) {}

  async create(input: UserCreateInput): Promise<User> {
    if (!input.email.includes('@')) throw new ValidationError('Invalid email');
    const existing = await this.db.users.findByEmail(input.email);
    if (existing) throw new ConflictError('Email already registered');
    return this.db.users.insert({ ...input, role: input.role ?? 'member' });
  }

  async findById(id: string): Promise<User | null> {
    if (!id) throw new ValidationError('ID is required');
    return this.db.users.findOne({ id });
  }

  async updateRole(id: string, role: 'admin' | 'member' | 'viewer'): Promise<User> {
    const user = await this.findById(id);
    if (!user) throw new NotFoundError(`User ${id} not found`);
    return this.db.users.update(id, { role });
  }

  async delete(id: string): Promise<void> {
    const user = await this.findById(id);
    if (!user) throw new NotFoundError(`User ${id} not found`);
    await this.db.users.softDelete(id);
  }

  async list(options?: { role?: string; limit?: number; offset?: number }): Promise<User[]> {
    return this.db.users.find(options ?? {});
  }
}
